import { useInfiniteQuery, useQuery } from '@tanstack/react-query';
import '../ProfilePage/myprofile.css';
import './visitProfile.css';
import { useAuth } from '../../Context/useAuth';
import { getFollowsData, getUserData, getUserJournals, getUserByUsername } from '../../../API/Api';
import { Fragment, useEffect, useRef } from 'react';
import { Outlet, useLocation, useNavigate, useParams } from 'react-router-dom';
import Sidebar from '../SideBar/Sidebar';
import { MoonLoader } from 'react-spinners';
import { useFollowMutation } from '../../utils/useMutation';
import debounce from '../../../helpers/debounce';
import VerifiedBadge from '../Badge/VerifiedBadge';
import formatCounts from '../../../helpers/fomatCounts';
import MobileNavlink from '../mobileNavLink/MobileNavLink';
import MobileSidebarLink from '../MobileSidebarLink/MobileSidebarLink';
import { useState } from 'react';
import WriteJournalButton from '../WriteJournalButton/WriteJournalButton';
import Editor from '../HomePage/Editor/Editor';
import Loader from '../loadingComponent/BgLoader';
import useProfileSeo from '../../seo/useProfileSeo';

const Visitprofile = () =>{
    const location = useLocation();
    const stateData = location.state;
    const { username: urlUsername } = useParams();
    const queryUserId = new URLSearchParams(location.search).get('userId');
    const isUsernameRoute = !!urlUsername;

    // Fetch user by username if on /@username route
    const { data: usernameData, isLoading: isLoadingByUsername } = useQuery({
        queryKey: ['userByUsername', urlUsername],
        queryFn: () => getUserByUsername(urlUsername),
        enabled: isUsernameRoute,
        staleTime: 1000 * 60 * 5,
        refetchOnWindowFocus: false,
    });

    // Resolve visitedUserId from either username lookup, state, or query param
    const visitedUserId = isUsernameRoute
        ? usernameData?.userData?.[0]?.id
        : (stateData?.userId || queryUserId);

    const resolvedUsername = isUsernameRoute
        ? urlUsername
        : usernameData?.userData?.[0]?.username;

    const {session, user, notifCount, loading} = useAuth();

    const [showSidebar, setShowSidebar]= useState(false)
    const [opendRichTextEditor, setOpenRichTextEditor] = useState(false);

    const buttonRef = useRef();

    const navigate = useNavigate();
    const visitedProfileNavState = { userId: visitedUserId };
    const visibleProfileSections = [{id: 'stats'}, {id: 'bio'}, {id: 'joined_date'}];

    // Use @username paths when available, fall back to legacy /visitProfile paths
    const profileUsername = resolvedUsername || usernameData?.userData?.[0]?.username;
    const useNewUrls = !!profileUsername;
    const tablists = useNewUrls
        ? [
            {label: 'Writings', path: `/u/${profileUsername}`, action: () => navigate(`/u/${profileUsername}`, {state: visitedProfileNavState})},
            {label: 'Media', path: `/u/${profileUsername}/media`, action: () => navigate(`/u/${profileUsername}/media`, {state: visitedProfileNavState})},
            {label: 'Collections', path: `/u/${profileUsername}/collections`, action: () => navigate(`/u/${profileUsername}/collections`, {state: visitedProfileNavState})},
            {label: 'Opinions', path: `/u/${profileUsername}/opinions`, action: () => navigate(`/u/${profileUsername}/opinions`, {state: visitedProfileNavState})}
        ]
        : [
            {label: 'Writings', path: '/visitProfile', action: () => navigate(`/visitProfile?userId=${visitedUserId || ''}`, {state: visitedProfileNavState})},
            {label: 'Media', path: '/visitProfile/media', action: () => navigate(`/visitProfile/media?userId=${visitedUserId || ''}`, {state: visitedProfileNavState})},
            {label: 'Collections', path: '/visitProfile/visitedCollections', action: () => navigate(`/visitProfile/visitedCollections?userId=${visitedUserId || ''}`, {state: visitedProfileNavState})},
            {label: 'Opinions', path:'/visitProfile/visitedOpinions', action: () => navigate(`/visitProfile/visitedOpinions?userId=${visitedUserId || ''}`, {state: visitedProfileNavState})}
        ]

     const navigatePath = (path) => {
        return navigate(path)
    }

    const handleMouseMove = (isFollowing) =>{
        if(buttonRef.current){
            if(isFollowing){
                buttonRef.current.innerText = 'Unfollow'
            } else {
                return
            }
        }
    }

    //open rich text editor
    const handleClickRichtextEditor = () =>{
        setOpenRichTextEditor(true);
    }
    //close rich text editor
    const handleCloseRichtextEditor = () =>{
        setOpenRichTextEditor(false);
    }

    // open sidebar through boolean function
    const openSidebar = () =>{
        setShowSidebar(true)
    }

    // close sidebar through boolean function
    const closeSidebar = () =>{
        setShowSidebar(false)
    }

    const handleMouseLeave = (isFollowing) =>{
        if(buttonRef.current){
            if(isFollowing){
                buttonRef.current.innerText = 'Following'
            } else {
                return
            }
        }
    }

    const mutationFollow = useFollowMutation(session);
    const hadnleClickFollow = (e, followingId, followerId,) =>{
        mutationFollow.mutate({followingId, followerId})
    }
    const debounceClickFollow = debounce(hadnleClickFollow, 0)

    const links = [
        {
            path: '/home', 
            label: 'Home', action: ()=> navigatePath('/home'), 
            icon: 
            <svg xmlns="http://www.w3.org/2000/svg" width="28px" height="28px" viewBox="0 0 24 24" fill="#000000ff">
                <g id="style=fill">
                    <g id="home-line" clipPath="url(#clip0_1_110)">
                        <path id="Subtract" fillRule="evenodd" clipRule="evenodd" d="M14.3594 2.12613C13.0087 0.944612 10.9923 0.94461 9.64162 2.12612L3.2802 7.69086C2.29508 8.55261 1.72998 9.79772 1.72998 11.1066L1.72998 19.1672C1.72998 21.1459 3.33403 22.75 5.31273 22.75L18.6883 22.75C20.667 22.75 22.271 21.1459 22.271 19.1672L22.271 11.1066C22.271 9.79772 21.706 8.55261 20.7208 7.69086L14.3594 2.12613ZM10 16.1136C9.58579 16.1136 9.25 16.4494 9.25 16.8636C9.25 17.2779 9.58579 17.6136 10 17.6136L14 17.6136C14.4142 17.6136 14.75 17.2779 14.75 16.8636C14.75 16.4494 14.4142 16.1136 14 16.1136L10 16.1136Z" fill={location.pathname === '/home' ? "var(--accent-dark)" : "var(--text-muted)"}/>
                    </g>
                </g>
            </svg>
        },
        {
            path: '/home/gallery',
            label: 'Gallery', action: ()=> navigatePath('/home/gallery'),
            icon:
            <svg xmlns="http://www.w3.org/2000/svg" width="28px" height="28px" viewBox="0 0 24 24" fill="none">
                <path d="M3 6.2C3 4.985 3.985 4 5.2 4H18.8C20.015 4 21 4.985 21 6.2V17.8C21 19.015 20.015 20 18.8 20H5.2C3.985 20 3 19.015 3 17.8V6.2Z" fill={location.pathname === '/home/gallery' ? "var(--accent-dark)" : "var(--text-muted)"} />
                <path d="M6.8 14.8L8.7 12.7C8.93 12.45 9.32 12.44 9.56 12.67L11.24 14.35L13.72 11.4C13.95 11.12 14.38 11.1 14.64 11.35L17.2 13.85V16.7H4.8V15.8L6.8 14.8Z" fill={location.pathname === '/home/gallery' ? "#eaf2ff" : "#d8d8d8"} />
                <circle cx="8.5" cy="8.8" r="1.2" fill={location.pathname === '/home/gallery' ? "#eaf2ff" : "#d8d8d8"} />
            </svg>
        },
        {
            path: '/profile', 
            label: 'Profile', action: ()=> navigatePath('/profile'), 
            icon: 
            <svg xmlns="http://www.w3.org/2000/svg" width="28px" height="28px" viewBox="0 0 24 24" fill="#000000ff">
                <g id="style=fill">
                    <g id="profile">
                        <path id="vector (Stroke)" fillRule="evenodd" clipRule="evenodd" d="M6.75 6.5C6.75 3.6005 9.1005 1.25 12 1.25C14.8995 1.25 17.25 3.6005 17.25 6.5C17.25 9.3995 14.8995 11.75 12 11.75C9.1005 11.75 6.75 9.3995 6.75 6.5Z" fill={location.pathname === '/profile' ? "var(--accent-dark)" : "var(--text-muted)"}/>
                        <path id="rec (Stroke)" fillRule="evenodd" clipRule="evenodd" d="M4.25 18.5714C4.25 15.6325 6.63249 13.25 9.57143 13.25H14.4286C17.3675 13.25 19.75 15.6325 19.75 18.5714C19.75 20.8792 17.8792 22.75 15.5714 22.75H8.42857C6.12081 22.75 4.25 20.8792 4.25 18.5714Z" fill={location.pathname === '/profile' ? "var(--accent-dark)" : "var(--text-muted)"}/>
                    </g>
                </g>
            </svg>
        },
        {
            path: '/home/notifications', 
            label: 'Notifications', 
            notifCount: notifCount > 0 ? notifCount : '',
            action: () => navigate('/home/notifications'),
            icon: 
            <svg xmlns="http://www.w3.org/2000/svg" width="28px" height="28px" viewBox="0 0 24 24" fill="#000000ff">
                <g id="style=fill">
                    <g id="notification-bell">
                        <path id="vector (Stroke)" fillRule="evenodd" clipRule="evenodd" d="M14.802 19.8317C15.4184 19.7699 15.8349 20.4242 15.5437 20.9539C15.3385 21.3271 15.0493 21.6529 14.7029 21.9197C14.3496 22.1918 13.9397 22.4006 13.5 22.5408C13.0601 22.6812 12.593 22.7522 12.1242 22.7522C11.6554 22.7522 11.1883 22.6812 10.7484 22.5408C10.3087 22.4006 9.89883 22.1918 9.54556 21.9197C9.1991 21.6529 8.90988 21.3271 8.70472 20.9539C8.41354 20.4242 8.83002 19.7699 9.44644 19.8317C9.63869 19.851 11.1433 19.9981 12.1242 19.9981C13.1051 19.9981 14.6097 19.851 14.802 19.8317Z" fill={location.pathname === '/home/notifications' ? "var(--accent-dark)" : "var(--text-muted)"}/>
                        <path id="vector (Stroke)_2" fillRule="evenodd" clipRule="evenodd" d="M8.52901 2.08755C10.7932 1.00445 13.4465 0.967602 15.7423 1.98737L15.9475 2.07851C18.3532 3.14707 19.8934 5.4622 19.8934 8.0096L19.8934 9.27297C19.8934 10.2885 20.1236 11.2918 20.5681 12.213L20.8335 12.7632C22.0525 15.29 20.465 18.2435 17.6156 18.7498L17.455 18.7783C13.93 19.4046 10.3154 19.4046 6.79044 18.7783C3.90274 18.2653 2.37502 15.1943 3.77239 12.7115L3.99943 12.3082C4.55987 11.3124 4.85335 10.1981 4.85335 9.06596L4.85335 7.79233C4.85335 5.3744 6.27704 3.16478 8.52901 2.08755Z" fill={location.pathname === '/home/notifications' ? "var(--accent-dark)" : "var(--text-muted)"}/>
                    </g>
                </g>
            </svg> 
        },
        {
            path: '/home/boomark', 
            label: 'Bookmarks', action: ()=> navigatePath('/home/bookmark'), 
            icon: 
            <svg xmlns="http://www.w3.org/2000/svg" width="28px" height="28px" viewBox="0 0 24 24" fill="none">
                <g id="style=fill">
                    <g id="bookmark">
                    <path id="Subtract" fillRule="evenodd" clipRule="evenodd" d="M8 1.25C5.37665 1.25 3.25 3.37665 3.25 6V20.4648C3.25 21.7269 4.27311 22.75 5.53518 22.75C5.98634 22.75 6.42739 22.6165 6.80278 22.3662L11.3066 19.3636C11.7265 19.0837 12.2735 19.0837 12.6934 19.3636L17.1972 22.3662C17.5726 22.6165 18.0137 22.75 18.4648 22.75C19.7269 22.75 20.75 21.7269 20.75 20.4648V6C20.75 3.37665 18.6234 1.25 16 1.25H8ZM9 6.75C8.58579 6.75 8.25 7.08579 8.25 7.5C8.25 7.91421 8.58579 8.25 9 8.25H15C15.4142 8.25 15.75 7.91421 15.75 7.5C15.75 7.08579 15.4142 6.75 15 6.75H9Z" fill={location.pathname === '/home/bookmark' ? "var(--accent-dark)" : "var(--text-muted)"}/>
                    </g>
                </g>
            </svg>
        },
        {
            path: '/home/collections',
            label: 'Collections',
            action: () => {navigatePath('/home/collections')},
            icon: 
            <svg xmlns="http://www.w3.org/2000/svg" xmlnsXlink="http://www.w3.org/1999/xlink" width="28px" height="28px" viewBox="0 0 24 24" version="1.1">
                <title>ic_fluent_book_formula_recent_24_filled</title>
                <desc>Created with Sketch.</desc>
                <g id="🔍-System-Icons" stroke="none" strokeWidth="1" fill="none" fillRule="evenodd">
                    <g id="ic_fluent_book_formula_recent_24_filled" fill={location.pathname === '/home/collections' ? "var(--accent-dark)" : "var(--text-muted)"} fillRule="nonzero">
                    <path d="M18,2 C19.3807,2 20.5,3.11929 20.5,4.5 L20.5,18.75 C20.5,19.1642 20.1642,19.5 19.75,19.5 L5.5,19.5 C5.5,20.0523 5.94772,20.5 6.5,20.5 L19.75,20.5 C20.1642,20.5 20.5,20.8358 20.5,21.25 C20.5,21.6642 20.1642,22 19.75,22 L6.5,22 C5.11929,22 4,20.8807 4,19.5 L4,4.5 C4,3.11929 5.11929,2 6.5,2 L18,2 Z M12.8581,6.37799 C12.62598,5.90759933 11.9844378,5.87623996 11.6977281,6.28391187 L11.642,6.37799 L10.5416,8.60759 L8.08108,8.96512 C7.55966125,9.04088875 7.33187629,9.64635672 7.63705678,10.0449565 L7.70527,10.1217 L9.48571,11.8572 L9.06541,14.3078 C8.97598882,14.8291176 9.48575824,15.2340394 9.96079283,15.0617758 L10.0493,15.0226 L12.25,13.8656 L14.4508,15.0226 C14.9189412,15.2688118 15.4615792,14.9090388 15.444597,14.4040705 L15.4347,14.3078 L15.0143,11.8572 L16.7948,10.1217 C17.17205,9.75395625 17.0005109,9.13023984 16.5193002,8.98711816 L16.419,8.96512 L13.9585,8.60759 L12.8581,6.37799 Z M12.25,8.21029 L12.9001,9.52747 C12.9847857,9.69901857 13.1371367,9.82544224 13.3180464,9.87827058 L13.4107,9.89842 L14.8643,10.1096 L13.8124,11.1349 C13.6792333,11.2647333 13.6064139,11.442275 13.6076569,11.625106 L13.6174,11.7351 L13.8657,13.1829 L12.5656,12.4993 C12.4009333,12.4128 12.2096,12.3983833 12.0361023,12.45605 L11.9345,12.4993 L10.6343,13.1829 L10.8826,11.7351 C10.9141,11.55185 10.8686556,11.3654056 10.7601556,11.2181856 L10.6876,11.1349 L9.6358,10.1096 L11.0894,9.89842 C11.2787429,9.87091429 11.4460449,9.76506816 11.5521994,9.60935207 L11.6,9.52747 L12.25,8.21029 Z" id="🎨-Color">
                    </path>
                    </g>
                </g>
            </svg>,
        },
        {
            label: 'Write', action: () => setOpenRichTextEditor(true), 
            className: 'write-journal-bttn'
        }, // the action function will set the state  to (true)and pass to the HOME.jsx when user clicks the function
    ]


    const {data, isLoading} = useQuery({
        queryKey: ['visitedProfile', visitedUserId],
        queryFn:({queryKey}) => getUserData(queryKey[1]),
        enabled: !!visitedUserId && !isUsernameRoute,
        refetchOnWindowFocus: false
    })

    // Use username-fetched data when on /@username route, otherwise use userId-fetched data
    const userData = isUsernameRoute
        ? usernameData?.userData?.[0]
        : data?.userData?.[0]

    useProfileSeo(userData, profileUsername);
    const getProfileSectionSize = () => 'md';

    const{data: followsData, isLoading: isLoadingFollowsData} = useQuery({
        queryKey: ['followsData', user?.userData?.[0].id, visitedUserId],
        queryFn: ({queryKey}) => getFollowsData(queryKey[1], queryKey[2]),
        staleTime: 1000 * 60 * 60,
        cacheTime: 1000 * 60 * 60,
        enabled: !!user?.userData?.[0].id && !!visitedUserId,
        refetchOnWindowFocus: false
    })


    useEffect(() =>{
        console.log(data)
    }, [data])

    useEffect(() => {
        if(!session && !loading){
            return navigate('/login')
            //check if the user has user metadata on the users table database if not then show a UI that let them input there data and save to database
        }

    },[session, loading])

    if(isLoading || isLoadingByUsername){
        return(
            <Loader/>
        )
    }
    return(
        <>{opendRichTextEditor &&(
            <Editor onClose={handleCloseRichtextEditor}/>
        )}

        <div className='profile-parent-container'>
            {userData?.background && (
                <div className="blurred-img-bg" style={userData?.background}/>
            )}

            <div className="side-bar-holder-container">
                <Sidebar links={links}/> {/*passing the setShowEditor to this component to be used as a state setter inside this component*/}
            </div>

            <div style={{color: userData?.profile_font_color}} className="profile-center-bar-container">
                {userData && (

                    <div style={userData?.background} className='visit-profile-hero-section'>

                        <div className='visited-profile-top-row'>
                            <div className={`profile-avatar-ring ${userData?.badge === 'legend' ? 'badge-ring-legend' : userData?.badge === 'og' ? 'badge-ring-og' : ''}`}>
                                <img className='visited-profile-image' src={userData?.image_url || '/assets/profile.jpg'} alt={`${userData?.name || "User"} profile picture`} />
                            </div>
                        </div>

                        <div className='visited-profile-name-container'>
                            <div className='visited-profile-name-row'>
                                <p className='visited-profile-name'>{userData?.name}</p>
                                <VerifiedBadge badge={userData?.badge} size={22} />
                                {userData?.badge && (
                                    <span className={`badge-pill ${userData.badge === 'legend' ? 'badge-pill-legend' : 'badge-pill-og'}`}>
                                        {userData.badge === 'legend' ? 'Legend' : 'OG'}
                                    </span>
                                )}
                            </div>
                        </div>

                        <div className='visited-profile-layout-sections'>
                            {visibleProfileSections.map((section) => {
                                const sectionSize = getProfileSectionSize(section.id);

                                if(section.id === 'stats'){
                                    return (
                                        <Fragment key={section.id}>
                                            <div className={`visited-profile-stats-container profile-section-size-${sectionSize}`}>
                                                <div className='visited-profile-stat-item'>
                                                    <span className='visited-stat-number'>{formatCounts(followsData?.followersCount)}</span>
                                                    <span className='visited-stat-label'>Followers</span>
                                                </div>
                                                <div className='visited-profile-stat-item'>
                                                    <span className='visited-stat-number'>{formatCounts(followsData?.followingsCount)}</span>
                                                    <span className='visited-stat-label'>Following</span>
                                                </div>
                                            </div>
                                        </Fragment>
                                    );
                                }

                                if(section.id === 'bio'){
                                    return (
                                        <Fragment key={section.id}>
                                            <div className={`visited-profile-bio-container profile-section-size-${sectionSize}`}>
                                                <p style={{margin: 0, padding: 0}}>{userData?.bio}</p>
                                            </div>
                                        </Fragment>
                                    );
                                }

                                if(section.id === 'joined_date'){
                                    return (
                                        <Fragment key={section.id}>
                                            <div className={`visited-profile-joined-date profile-section-size-${sectionSize}`}>
                                                <p className='visited-profile-date-joined'>{new Date(userData?.created_at).toLocaleDateString('en-US', {
                                                    month: 'long',
                                                    day: '2-digit',
                                                    year: 'numeric'
                                                })}</p>
                                            </div>
                                        </Fragment>
                                    );
                                }

                                return null;
                            })}
                        </div>

                        <div className='visited-profile-actions-row'>
                            <div onMouseMove={() => handleMouseMove(followsData?.isFollowing)} onMouseLeave={() => handleMouseLeave(followsData?.isFollowing)} className='visited-profile-follow-button-container'>
                                <button onClick={(e) => debounceClickFollow(e, visitedUserId, user?.userData?.[0].id)} ref={buttonRef} className={followsData?.isFollowing ? 'unfollow-visited-profile-bttn' : 'follow-visited-profile-bttn'}>
                                    {followsData?.isFollowing ? 'Following' : 'Follow'}
                                </button>
                            </div>
                        </div>

                    </div>

                    )
                }

                <div className='my-profile-tablist'>
                    {tablists.map((tab, index) => (
                         <div key={index} onClick={() => tab.action()} className='tab-container'>
                            {tab.label}
                            <div className={location.pathname === tab.path ? 'tab-indicator' : ''}/>
                        </div>
                    ))}

                </div>

                <Outlet/>

            </div>

            <div className="profile-sidebar-right-holder-container" />

            {showSidebar && (
                <MobileSidebarLink onclose={closeSidebar}/>
            )}

            {<MobileNavlink clickOpenSidebar={openSidebar}/>}
            <WriteJournalButton onOpen={handleClickRichtextEditor}/>
        </div>
        </>

    )
}
export default Visitprofile;

