}
.profile-editor-close-button-container{
    display: flex;
    justify-content: flex-end;
    align-items: center;
    height: fit-content;
}
.profile-editor-close-button{
    display: flex;
    justify-content: center;
    align-items: center;
    transition: background-color 0.2s ease, transform 0.2s ease, color 0.2s ease;
    padding: 0.5rem;
    cursor: pointer;
    border-radius: 50%;
    color: var(--text-secondary);
}
.profile-editor-close-button:hover{
    background-color: var(--bg-hover);
    color: var(--text-primary);
    transform: rotate(90deg);
}
.profile-editor-close-button:active{
    transform: rotate(90deg) scale(0.9);
}
.profile-edit-image-container{
    display: flex;
    position: relative;
    justify-content: space-between;
    align-items: flex-start;
    height: fit-content;
    width: 100%;
    border-radius: 20px;
}
.add-profile-background{
    display: flex;
    justify-content: center;
    align-items: center;
    gap: 0.35rem;
    padding: 0.45rem 0.8rem;
    border-radius: 20px;
    background-color: transparent;
    border: 1.5px solid var(--border-light);
    cursor: pointer;
    font-family: "Lexend Deca", sans-serif;
    font-weight: 500;
    font-size: 0.8rem;
    color: var(--text-primary);
    transition: background-color 0.15s ease;
}
.add-profile-background:hover{
    background-color: var(--bg-glass);
}
.profile-edit-image-child-container{
    display: flex;
    justify-content: center;
    align-content: center;
    border-radius: 20px;
}
.profile-edit-image-bg{
    display: flex;
    justify-content: center;
    align-items: center;
    position: absolute;
    width: 130px;
    height: 130px;
    background-color: rgba(120, 120, 120, 0.588);
    z-index: 2;
    border-radius: 50%;
