}
.input-identifier{
    display: flex;
    justify-content: center;
    align-items: center;
}
.input-identifier p{
    margin: 0;
    padding: 0;
    font-family: "Lexend Deca", sans-serif;
    font-size: 0.75rem;
    font-weight: 500;
    color: var(--text-secondary);
}
.profile-edit-name-length{
    display: flex;
    justify-content: center;
    align-items: center;
    margin-right: 0.2rem;
}
.profile-edit-name-length p{
    margin: 0;
    padding: 0;
    font-size: 0.8rem;
    color: var(--text-muted);
}
.edit-profile-input{
    border: none;
    background-color: transparent;
    color: var(--text-primary);
    padding: 0 0.5rem 0.5rem 0.5rem;
    font-family: "Lexend Deca", sans-serif;
    font-size: 1.5rem;
    font-weight: 600;
    width: fit-content;
}
.edit-profile-input:focus{
    outline: none;
}
.edit-profile-input-bio-container{
    display: flex;
    flex-direction: column;
    justify-content: flex-start;
    align-items:center;
    width: 100%;
    height: 200px;
    border: 1px solid var(--border-light);
    border-radius: 8px;
    background-color: var(--bg-glass);
    backdrop-filter: blur(25px);
    -webkit-backdrop-filter: blur(25px);
}
.input-bio-identifier-container{
    display: flex;
    justify-content: space-between;
    width: 98%;
    height: fit-content;
}
.bio-textarea{
    width: 98%;
    height: 100%;
    resize: none;
    background-color: transparent;
    border: none;
    color: var(--text-primary);
    font-family: var(--font-ui);
    font-size: 1rem;
}
.bio-textarea:focus{
    outline: none;
}
.bio-identifier p{
    padding: 0;
    margin: 0;
    font-family: "Lexend Deca", sans-serif;
    font-size: 0.75rem;
    font-weight: 500;
    color: var(--text-secondary);
}
.profile-edit-bio-length{
    display: flex;
    justify-content: center;
    height: fit-content;
    width: fit-content;
    align-items: center;
}
.profile-edit-bio-length p {
    padding: 0;
    margin: 0;
    font-size: 0.8rem;
    color: var(--text-muted);
}

.profile-edit-save-bttn{
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 0.6rem;
    border-radius: 12px;
    color: var(--bg-primary);
    background-color: var(--accent-dark);
    cursor: pointer;
    user-select: none;
    font-family: "Lexend Deca", sans-serif;
    font-weight: 600;
    font-size: 0.9rem;
    transition: background-color 0.2s ease, transform 0.2s ease, box-shadow 0.2s ease;
}
.profile-edit-save-bttn:hover{
    background-color: var(--accent-dark-hover);
    transform: translateY(-1px);
    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.12);
}
.profile-edit-save-bttn:active{
    transform: translateY(0);
    box-shadow: none;
}

.my-profile-tablist{
    display: flex;
    justify-content: flex-start;
    align-items: center;
    gap: 0.25rem;
    width: 90%;
    padding: 0.5rem;
    min-height: 40px;
    background-color: var(--bg-glass);
    backdrop-filter: blur(25px);
    -webkit-backdrop-filter: blur(25px);
    margin-top: 1rem;
    border-radius: 14px;
    border: 0.7px solid var(--border-light);
}
.tab-container{
    position: relative;
    display: flex;
    flex-direction: column;
    width: fit-content;
    height: fit-content;
    justify-content: center;
    align-items: center;
    padding: 0.5rem 1rem;
    margin: 0;
    cursor: pointer;
    user-select: none;
    font-family: "Lexend Deca", sans-serif;
    font-weight: 500;
    font-size: 0.82rem;
    border-radius: 10px;
    transition: background-color 0.2s ease, opacity 0.2s ease;
    opacity: 0.65;
}
.tab-container:hover{
    background-color: var(--bg-glass);
    opacity: 0.85;
}
.tab-indicator{
    bottom: -2px;
    position: absolute;
    display: flex;
    width: 60%;
    height: 3px;
    border-radius: 3px;
    background-color: currentColor;
    opacity: 0.8;
    transition: width 0.25s ease, opacity 0.25s ease;
}
.tab-container:has(.tab-indicator){
    opacity: 1;
    font-weight: 600;
}

.profile-media-section{
    width: 90%;
    margin: 1rem 0 1.4rem;
    padding: 0.9rem;
    border-radius: 18px;
    border: 0.7px solid var(--border-light);
    background-color: var(--bg-glass);
    backdrop-filter: blur(22px);
    -webkit-backdrop-filter: blur(22px);
}
.profile-media-header-row{
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.65rem;
}
.profile-media-heading{
    margin: 0;
    padding: 0;
    font-family: "Lexend Deca", sans-serif;
    font-size: 1.75rem;
    font-weight: 700;
    line-height: 1.1;
    letter-spacing: -0.02em;
}
.profile-media-count{
    font-family: var(--font-ui);
    font-size: 1.2rem;
    font-weight: 600;
    opacity: 0.7;
}
.profile-media-warning{
    margin: 0 0 0.5rem;
    font-family: var(--font-ui);
    font-size: 0.78rem;
    opacity: 0.78;
}
.profile-media-empty-state{
    margin: 0;
    padding: 1rem 0.25rem 0.25rem;
    font-family: var(--font-ui);
    font-size: 0.85rem;
    opacity: 0.75;
}
.profile-media-grid{
    display: grid;
    grid-template-columns: repeat(3, minmax(0, 1fr));
    gap: 0.25rem;
}
.profile-media-grid-item{
    position: relative;
    width: 100%;
    aspect-ratio: 1 / 1;
    border-radius: 8px;
    overflow: hidden;
    background-color: rgba(0, 0, 0, 0.07);
}
.profile-media-grid-image-button{
    width: 100%;
    height: 100%;
    border: none;
    padding: 0;
    margin: 0;
    cursor: pointer;
    background: transparent;
}
.profile-media-image{
    width: 100%;
    height: 100%;
    object-fit: cover;
    display: block;
    transition: transform 0.2s ease, filter 0.2s ease;
}
.profile-media-grid-item:hover .profile-media-image{
    transform: scale(1.03);
    filter: saturate(1.04);
}
.profile-media-item-actions{
    position: absolute;
    top: 0.35rem;
    right: 0.35rem;
    z-index: 4;
}
.profile-media-item-settings-btn{
    width: 28px;
    height: 28px;
    display: flex;
    align-items: center;
    justify-content: center;
    border: none;
    border-radius: 50%;
    cursor: pointer;
    color: #ffffff;
    background-color: rgba(0, 0, 0, 0.46);
    transition: background-color 0.15s ease;
}
.profile-media-item-settings-btn:hover{
    background-color: rgba(0, 0, 0, 0.72);
}
.profile-media-item-settings-menu{
    margin-top: 0.28rem;
    min-width: 116px;
    border-radius: 8px;
    overflow: hidden;
    border: 0.7px solid rgba(255, 255, 255, 0.18);
    background-color: rgba(14, 14, 14, 0.95);
    box-shadow: 0 10px 24px rgba(0, 0, 0, 0.35);
}
.profile-media-item-delete-btn{
    width: 100%;
    border: none;
    padding: 0.52rem 0.65rem;
    text-align: left;
    font-family: var(--font-ui);
    font-size: 0.78rem;
    cursor: pointer;
    color: #ffb4b4;
    background-color: transparent;
}
.profile-media-item-delete-btn:hover{
    background-color: rgba(255, 77, 77, 0.18);
}
.profile-media-grid-loading-item{
    cursor: default;
    animation: mediaPulse 1.1s ease-in-out infinite;
}
@keyframes mediaPulse{
    0%{ opacity: 0.45; }
    50%{ opacity: 0.95; }
    100%{ opacity: 0.45; }
}
.profile-media-lightbox-overlay{
    position: absolute;
    inset: 0;
    z-index: 180;
    display: flex;
    justify-content: center;
    align-items: center;
    background-color: rgba(0, 0, 0, 0.7);
    backdrop-filter: blur(3px);
    -webkit-backdrop-filter: blur(3px);
    padding: 1rem;
}
.profile-media-lightbox-dialog{
    position: relative;
    width: min(94vw, 1100px);
    max-height: 92vh;
    border-radius: 14px;
    overflow: hidden;
    background-color: rgba(12, 12, 12, 0.92);
    border: 0.7px solid rgba(255, 255, 255, 0.22);
    box-shadow: 0 20px 48px rgba(0, 0, 0, 0.4);
}
